SELECT SEQ AS seq , NAME , model_id AS modelId , data_cnt AS dataCnt , requested_at AS requestedAt , started_at as startecAt , ended_at as endedAt , duration , status , is_success as isSuccess , cer , wer , detail FROM TB_CS_TRAIN WHERE requested_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND status < #{search.searchText}
order by requested_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

