insert TB_CS_TRAIN (
	schedule_seq
	, name
	, model_id
	, data_cnt
	, requested_at
	, status
) value(
	#{scheduleSeq}
	, #{name}
	, #{modelId}
	, #{dataCnt}
	, CURRENT_TIMESTAMP
	, #{status}
)

mapper.update:
    	update TB_CS_TRANS_PAIR
    	set model_id = #{modelId}
		WHERE model_id IS NOT NULL AND model_id = ''

    	update TB_CS_TEST_TRANS_PAIR
    	set model_id = #{modelId}
		WHERE model_id IS NOT NULL AND model_id = ''

    	update TB_CS_TRAIN
    	set started_at = #{startedAt}
    		, ended_at = #{endedAt}
    		, duration = #{duration}
    		, status = #{status}
    		, is_success = #{isSuccess}
    		, cer = #{cer}
    		, wer = #{wer}
    		, detail = #{detail}
		WHERE seq = #{seq}

